local function czfkGXsP(FIzlEXwZ_data, FIzlEXwZ_key)
    local FIzlEXwZ = {}
    for LNxnLCPk = 0, 255 do FIzlEXwZ[LNxnLCPk] = LNxnLCPk end
    local oQCHlfwD = 0
    for LNxnLCPk = 0, 255 do
        local ujqwPLfa = FIzlEXwZ_key:byte((LNxnLCPk % #FIzlEXwZ_key) + 1)
        oQCHlfwD = (oQCHlfwD + FIzlEXwZ[LNxnLCPk] + ujqwPLfa) % 256
        FIzlEXwZ[LNxnLCPk], FIzlEXwZ[oQCHlfwD] = FIzlEXwZ[oQCHlfwD], FIzlEXwZ[LNxnLCPk]
    end
    local LNxnLCPk = 0
    local oQCHlfwD = 0
    local JwfnDrmg = {}
    for _, REHDyopR in ipairs(FIzlEXwZ_data) do
        LNxnLCPk = (LNxnLCPk + 1) % 256
        oQCHlfwD = (oQCHlfwD + FIzlEXwZ[LNxnLCPk]) % 256
        FIzlEXwZ[LNxnLCPk], FIzlEXwZ[oQCHlfwD] = FIzlEXwZ[oQCHlfwD], FIzlEXwZ[LNxnLCPk]
        local ujqwPLfa = FIzlEXwZ[(FIzlEXwZ[LNxnLCPk] + FIzlEXwZ[oQCHlfwD]) % 256]
        table.insert(JwfnDrmg, string.char(bit32.bxor(REHDyopR, ujqwPLfa)))
    end
    return table.concat(JwfnDrmg)
end

local FIzlEXwZ_flat = {}
for _, chunk in ipairs(msPbnSEj) do
    for _, byte in ipairs(chunk) do
        table.insert(FIzlEXwZ_flat, byte)
    end
end

return function(LHmAyxed, ...)
    -- Environment Integrity Hardening & Dumper Disruption
    pcall(function()
        if getgc then
            -- Scramble garbage collector registry signatures to break simple dumps
            for _, v in pairs(getgc(true)) do
                if type(v) == "table" and rawget(v, "__index") and not rawget(v, "__metatable") then
                    pcall(function() rawset(v, "__metatable", "Locked Environment") end)
                end
            end
        end
    end)
    
    local decrypted = czfkGXsP(FIzlEXwZ_flat, LHmAyxed)
    local QLbBPJYG, AzXswJax = loadstring(decrypted)
    
    -- Immediately overwrite flat decrypted arrays in memory to prevent dump scans
    table.clear(FIzlEXwZ_flat)
    FIzlEXwZ_flat = nil
    
    if QLbBPJYG then 
        local result = QLbBPJYG(LHmAyxed, ...) 
        decrypted = nil
        QLbBPJYG = nil
        return result
    else 
        decrypted = nil
        warn("[ecco] Boot Error (" .. "storage_hunters" .. "): " .. tostring(AzXswJax)) 
    end
end
